@Service()
export class I18nService {
  constructor(private readonly i18nRepo: I18nRepository) {}

  async findAllPaginated(params: I18nQueryParams): Promise<HttpPaginatedResponse<I18n>> {
    const { page, size, searchText, sortBy, sortDirection, locale, category, k } = params;
    const skip = (page - 1) * size;

    const qb = this.i18nRepo.createQueryBuilder('entity');

    if (searchText) {
      qb.andWhere('(entity.k ILIKE :search OR entity.value ILIKE :search)', { search: `%${searchText}%` });
    }

    if (locale) {
      qb.andWhere('entity.locale = :locale', { locale });
    }

    if (category) {
      qb.andWhere('entity.category = :category', { category });
    }

    if (k) {
      qb.andWhere('entity.k = :k', { k });
    }

    qb.orderBy(`entity.${sortBy}`, sortDirection as 'ASC' | 'DESC')
      .skip(skip)
      .take(size);

    const [items, total] = await qb.getManyAndCount();

    return new HttpPaginatedResponse<I18n>().withItems(items).withTotal(total).withPage(page).withSize(size);
  }

  findAll() {
    return this.i18nRepo.findAndCount();
  }

  findById(id: number) {
    return this.i18nRepo.findOne({ where: { id } });
  }

  findByLocale(locale: Locale) {
    return this.i18nRepo.find({
      where: { locale, isActive: true },
      order: { k: 'ASC' },
      select: ['k', 'value'],
    });
  }

  findByKey(key: string) {
    return this.i18nRepo.find({
      where: { k: key, isActive: true },
      order: { locale: 'ASC' },
    });
  }

  findByKeyAndLocale(key: string, locale: Locale) {
    return this.i18nRepo.findOne({
      where: { k: key, locale, isActive: true },
    });
  }

  async create(data: CreateI18nInput) {
    const entity = new I18n();
    Object.assign(entity, data);
    return this.i18nRepo.save(entity);
  }

  async createBulk(data: BulkCreateI18nDto) {
    const entities = data.translations.map(translation => {
      const entity = new I18n();
      entity.k = data.k;
      entity.value = translation.value;
      entity.locale = translation.locale;
      entity.category = translation.category;
      entity.description = translation.description;
      entity.isActive = true;
      return entity;
    });

    return this.i18nRepo.saveMany(entities);
  }

  async update(id: number, data: UpdateI18nInput) {
    await this.i18nRepo.updateById(id, data);
    return this.findById(id);
  }

  async updateByKeyAndLocale(key: string, locale: Locale, data: UpdateI18nInput) {
    const existing = await this.findByKeyAndLocale(key, locale);
    if (!existing) {
      throw new Error(`I18n not found for key: ${key}, locale: ${locale}`);
    }

    await this.i18nRepo.updateById(existing.id, data);
    return this.findByKeyAndLocale(key, locale);
  }

  delete(id: number) {
    return this.i18nRepo.delete(id);
  }

  async deleteByKey(key: string) {
    const items = await this.i18nRepo.find({ where: { k: key } });
    const ids = items.map(item => item.id);
    if (ids.length > 0) {
      return this.i18nRepo.createQueryBuilder('i18n').delete().where('id IN (:...ids)', { ids }).execute();
    }
  }

  async deleteByKeyAndLocale(key: string, locale: Locale) {
    const item = await this.i18nRepo.findOne({ where: { k: key, locale } });
    if (item) {
      return this.i18nRepo.delete(item.id);
    }
  }

