import { JsonController, Get, Post, Put, Delete, Param, Body, QueryParams, OnUndefined } from 'routing-controllers';
import { OpenAPI } from 'routing-controllers-openapi';
import { Service } from 'typedi';

import { HttpPaginatedResponse } from '@Libs/types/HttpPaginatedResponse';

import { Locale } from '@Enums/Locale';

import { I18n } from '@Entities/I18n';

import { I18nService } from '@Services/I18nService';

import { I18nQueryParams, CreateI18nDto, UpdateI18nDto, BulkCreateI18nDto } from '@Rests/types/I18nDto';

@Service()
@JsonController('/i18n')
export class I18nController {
  constructor(private readonly service: I18nService) {}

  @Get('')
  @OpenAPI({ summary: 'List I18n (paginated)' })
  list(@QueryParams() params: I18nQueryParams): Promise<HttpPaginatedResponse<I18n>> {
    return this.service.findAllPaginated(params);
  }

  @Get('/by-locale/:locale')
  @OpenAPI({ summary: 'Get all I18n by locale' })
  async getByLocale(@Param('locale') locale: Locale): Promise<Record<string, string>> {
    const items = await this.service.findByLocale(locale);
    return items.reduce((acc, item) => {
      acc[item.k] = item.value;
      return acc;
    }, {} as Record<string, string>);
  }

  @Get('/by-key/:key')
  @OpenAPI({ summary: 'Get all translations for a key' })
  getByKey(@Param('key') key: string) {
    return this.service.findByKey(key);
  }

  @Post('/sync')
  @OpenAPI({ summary: 'Sync I18n' })
  sync() {
    return this.service.sync();
  }

  @Get('/:id')
  @OpenAPI({ summary: 'Get I18n by id' })
  get(@Param('id') id: number) {
    return this.service.findById(id);
  }

  @Post('')
  @OpenAPI({ summary: 'Create I18n' })
  create(@Body({ validate: true }) dto: CreateI18nDto) {
    return this.service.create(dto);
  }

  @Post('/bulk')
  @OpenAPI({ summary: 'Create multiple translations for a key' })
  createBulk(@Body({ validate: true }) dto: BulkCreateI18nDto) {
    return this.service.createBulk(dto);
  }

  @Put('/:id')
  @OpenAPI({ summary: 'Update I18n' })
  update(@Param('id') id: number, @Body({ validate: true }) dto: UpdateI18nDto) {
    return this.service.update(id, dto);
  }

  @Delete('/:id')
  @OnUndefined(204)
  @OpenAPI({ summary: 'Delete I18n' })
  remove(@Param('id') id: number) {
    return this.service.delete(id);
  }
}

